#include<bits/stdc++.h>
using namespace std;
int n,k;
int dp[201][201];
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<=k;i++)
    {
        dp[i][1]=1;
    }
    for(int i=1;i<=k;i++)
    {
        for(int j=3;j<=n;j+=2)
        {
            for(int k=1;k<=j-2;k+=2)
            {
                dp[i][j]=(dp[i][j]+dp[i-1][k]*dp[i-1][j-k-1])%9901;
            }
        }
    }
    printf("%d",((dp[k][n]-dp[k-1][n])%9901+9901)%9901);
    return 0;
}
